import React, { useState } from 'react';
import { Search, Coffee, Sparkles } from 'lucide-react';
import { GitHubRepo } from '../types';
import RepoCard from './RepoCard';
import { motion } from 'framer-motion';

interface RepoGridProps {
  repos: GitHubRepo[];
  pinnedRepos: GitHubRepo[];
  tags: Record<string, string>;
}

const RepoGrid: React.FC<RepoGridProps> = ({ repos, pinnedRepos, tags }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const filterRepo = (repo: GitHubRepo) => 
    repo.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    (repo.description && repo.description.toLowerCase().includes(searchTerm.toLowerCase()));

  const filteredPinned = pinnedRepos.filter(filterRepo);
  const filteredOthers = repos.filter(r => !pinnedRepos.some(p => p.name === r.name)).filter(filterRepo);

  return (
    <section id="repos" className="py-24 bg-white dark:bg-coffee-950 rounded-t-[5rem] shadow-[0_-20px_80px_-20px_rgba(0,0,0,0.1)] relative z-10 -mt-10">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

        <div className="flex flex-col md:flex-row justify-between items-center mb-20 gap-10">
            <div className="text-center md:text-left">
                <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-coffee-100 dark:bg-coffee-900 text-coffee-700 dark:text-coffee-300 rounded-full text-xs font-black uppercase tracking-tighter mb-4">
                  <Sparkles size={14} />
                  <span>Curated Collections</span>
                </div>
                <h2 className="text-5xl sm:text-6xl font-display font-black text-coffee-950 dark:text-coffee-50 tracking-tight leading-none">
                    The Archive
                </h2>
                <p className="mt-4 text-coffee-500 dark:text-coffee-400 text-lg font-serif italic">Every batch of code, roasted to perfection.</p>
            </div>

            <div className="relative w-full md:w-96 group">
                <Search size={22} className="absolute left-5 top-1/2 -translate-y-1/2 text-coffee-400 group-focus-within:text-coffee-800 dark:group-focus-within:text-coffee-200 transition-colors" />
                <input
                    type="text"
                    placeholder="Search the cellar for specific roasts..."
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="w-full pl-14 pr-8 py-5 bg-coffee-50 dark:bg-coffee-900/50 border-2 border-transparent focus:border-coffee-200 dark:focus:border-coffee-800 rounded-[2rem] outline-none transition-all dark:text-white font-medium shadow-inner"
                />
            </div>
        </div>

        {filteredPinned.length > 0 && (
          <div className="mb-20">
            <div className="flex items-center gap-4 mb-10">
              <h3 className="text-sm font-black uppercase tracking-[0.4em] text-coffee-400">Signature Series</h3>
              <div className="h-px flex-1 bg-coffee-100 dark:bg-coffee-900" />
            </div>
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
              {filteredPinned.map(repo => (
                  <RepoCard key={`pin-${repo.name}`} repo={repo} isPinned={true} tag={tags[repo.name]} />
              ))}
            </div>
          </div>
        )}

        <div>
          <div className="flex items-center gap-4 mb-10">
            <h3 className="text-sm font-black uppercase tracking-[0.4em] text-coffee-400">Seasonal Blends</h3>
            <div className="h-px flex-1 bg-coffee-100 dark:bg-coffee-900" />
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
              {filteredOthers.slice(0, 21).map((repo, idx) => (
                  <motion.div
                    key={repo.id}
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ delay: idx % 3 * 0.1 }}
                  >
                    <RepoCard repo={repo} tag={tags[repo.name]} />
                  </motion.div>
              ))}
          </div>
        </div>

        {filteredPinned.length === 0 && filteredOthers.length === 0 && (
          <div className="text-center py-40">
             <div className="inline-block p-6 bg-coffee-50 dark:bg-coffee-900 rounded-full mb-6">
                <Coffee size={48} className="text-coffee-300" />
             </div>
             <p className="text-xl font-display text-coffee-400">The cellar is empty for this search.</p>
          </div>
        )}
      </div>
    </section>
  );
};

export default RepoGrid;

import React, { useState, useEffect, useCallback } from 'react';
import { AnimatePresence, motion } from 'framer-motion';
import { ChevronUp } from 'lucide-react';
import { getPortfolioData, RateLimitError } from './services/githubService';
import { GitHubUser, GitHubRepo } from './types';
import CoffeeLoader from './components/CoffeeLoader';
import Navbar from './components/Navbar';
import ProfileHero from './components/ProfileHero';
import RepoGrid from './components/RepoGrid';
import FollowersList from './components/FollowersList';

const App: React.FC = () => {
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<GitHubUser | null>(null);
  const [repos, setRepos] = useState<GitHubRepo[]>([]);
  const [pinnedRepos, setPinnedRepos] = useState<GitHubRepo[]>([]);
  const [followers, setFollowers] = useState<GitHubUser[]>([]);
  const [tags, setTags] = useState<Record<string, string>>({});
  const [error, setError] = useState<string | null>(null);
  const [rateLimitReset, setRateLimitReset] = useState<number | null>(null);
  const [currentView, setCurrentView] = useState<'home' | 'followers'>('home');
  const [isDark, setIsDark] = useState(false);
  const [showScrollTop, setShowScrollTop] = useState(false);
  const [ripple, setRipple] = useState<{ x: number, y: number, show: boolean }>({ x: 0, y: 0, show: false });

  useEffect(() => {
    const handleScroll = () => setShowScrollTop(window.scrollY > 300);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const loadData = useCallback(async (isInitial: boolean = false, forceRefresh: boolean = false) => {
    if (isInitial) setLoading(true);
    // User requested exactly 4 seconds loader
    const minLoadTime = isInitial ? new Promise(resolve => setTimeout(resolve, 4000)) : Promise.resolve();

    try {
      const [data] = await Promise.all([getPortfolioData(forceRefresh), minLoadTime]);
      setUser(data.user);
      setRepos(data.repos);
      setPinnedRepos(data.pinnedRepos);
      setFollowers(data.followers);
      setTags(data.tags || {});
      setError(null);
    } catch (err: any) {
      if (err instanceof RateLimitError) setRateLimitReset(err.resetTime);
      else setError("Network Error");
    } finally {
      if (isInitial) setLoading(false);
    }
  }, []);

  useEffect(() => { loadData(true); }, [loadData]);

  const toggleTheme = (event?: React.MouseEvent) => {
    const x = event?.clientX || window.innerWidth / 2;
    const y = event?.clientY || 60;

    document.body.classList.add('theme-transitioning');

    setRipple({ x, y, show: true });
    setTimeout(() => {
      const nextMode = !isDark;
      setIsDark(nextMode);
      document.documentElement.classList.toggle('dark', nextMode);
      setTimeout(() => {
        setRipple(prev => ({ ...prev, show: false }));
        document.body.classList.remove('theme-transitioning');
      }, 800);
    }, 10);
  };

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <>
      <AnimatePresence>
        {ripple.show && (
          <motion.div
            initial={{ clipPath: `circle(0% at ${ripple.x}px ${ripple.y}px)` }}
            animate={{ clipPath: `circle(150% at ${ripple.x}px ${ripple.y}px)` }}
            exit={{ opacity: 0 }}
            transition={{ duration: 0.8, ease: "easeInOut" }}
            className="fixed inset-0 z-[100] bg-coffee-900 dark:bg-coffee-100 pointer-events-none opacity-10"
          />
        )}
      </AnimatePresence>

      <AnimatePresence mode="wait">
        {loading && (
          <motion.div key="loader" exit={{ opacity: 0, scale: 1.1 }} transition={{ duration: 0.6 }} className="fixed inset-0 z-[100]">
            <CoffeeLoader />
          </motion.div>
        )}
      </AnimatePresence>

      {!loading && user && (
        <div className="min-h-screen bg-coffee-50 dark:bg-coffee-950 transition-colors duration-1000">
          <Navbar 
            user={user} isDark={isDark} toggleTheme={toggleTheme} 
            currentView={currentView} setView={setCurrentView}
            onRefresh={() => loadData(false, true)}
          />

          <main className="relative">
            <ProfileHero user={user} setView={setCurrentView} />

            <AnimatePresence mode="wait">
              <motion.div
                key={currentView}
                initial={{ opacity: 0, y: 40 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -40 }}
                transition={{ duration: 0.6, ease: [0.22, 1, 0.36, 1] }}
              >
                {currentView === 'home' ? (
                  <RepoGrid repos={repos} pinnedRepos={pinnedRepos} tags={tags} />
                ) : (
                  <FollowersList followers={followers} />
                )}
              </motion.div>
            </AnimatePresence>
          </main>

          <footer className="py-20 bg-coffee-950 text-coffee-400 text-center border-t border-coffee-900">
            <div className="max-w-7xl mx-auto px-4">
               <p className="font-display font-bold text-coffee-200 mb-2">PRO-GRAMMER-SD</p>
               <p className="text-xs tracking-widest uppercase mb-8">Crafted with caffeine and curiosity</p>
               <div className="flex justify-center gap-6">
                 <a href={`https://github.com/${user.login}`} target="_blank" className="hover:text-white transition-colors">GitHub</a>
                 <span className="text-coffee-800">•</span>
                 <a href="#" className="hover:text-white transition-colors">LinkedIn</a>
                 <span className="text-coffee-800">•</span>
                 <a href="#" className="hover:text-white transition-colors">Twitter</a>
               </div>
            </div>
          </footer>

          <AnimatePresence>
            {showScrollTop && (
              <motion.button
                initial={{ scale: 0, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                exit={{ scale: 0, opacity: 0 }}
                onClick={scrollToTop}
                className="fixed bottom-8 right-8 p-5 bg-coffee-900 dark:bg-coffee-100 text-white dark:text-coffee-950 rounded-full shadow-[0_10px_30px_rgba(0,0,0,0.3)] z-50 hover:scale-110 active:scale-90 transition-all group"
              >
                <ChevronUp size={24} className="group-hover:-translate-y-1 transition-transform" />
              </motion.button>
            )}
          </AnimatePresence>
        </div>
      )}
    </>
  );
};

export default App;

import React, { useEffect, useRef } from 'react';
import lottie from 'lottie-web';

const CoffeeLottie: React.FC = () => {
  const container = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!container.current) return;
    const anim = lottie.loadAnimation({
      container: container.current,
      renderer: 'svg',
      loop: true,
      autoplay: true,
      path: 'https://assets9.lottiefiles.com/packages/lf20_96bovdur.json'
    });
    return () => anim.destroy();
  }, []);

  return <div ref={container} className="w-32 h-32 mx-auto" />;
};

export default CoffeeLottie;

import React, { useState, useMemo } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Star, GitFork, GitBranch, ChevronDown, Check, Pin, Tag, ExternalLink, Terminal } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeRaw from 'rehype-raw';
import { GitHubRepo } from '../types';
import { fetchReadme, analyzeRepo } from '../services/githubService';

interface RepoCardProps {
  repo: GitHubRepo;
  isPinned?: boolean;
  tag?: string;
}

const RepoCard: React.FC<RepoCardProps> = ({ repo, isPinned = false, tag }) => {
  const [expanded, setExpanded] = useState(false);
  const [readme, setReadme] = useState<string | null>(null);
  const [readmeBranch, setReadmeBranch] = useState<string>('main');
  const [loadingReadme, setLoadingReadme] = useState(false);
  const [copied, setCopied] = useState(false);

  const analysis = analyzeRepo(repo);

  const activityData = useMemo(() => {
    const seed = repo.id;
    return Array.from({ length: 12 }, (_, i) => {
      const val = Math.abs(Math.sin(seed + i)) * (repo.stargazers_count + 1);
      return Math.min(Math.max(val % 10, 2), 10);
    });
