                    </motion.div>
                </div>

                <div className="mt-4 w-full">
                    <CoffeeLottie />
                </div>

                <h1 className="mt-4 text-4xl sm:text-6xl font-serif font-extrabold text-coffee-900 dark:text-coffee-50 italic">
                  {user.name || user.login}
