                <div className="flex items-center gap-1.5">
                    <GitFork size={16} className="text-coffee-500" />
                    <span className="font-bold text-sm sm:text-base text-coffee-800 dark:text-coffee-200">{repo.forks_count}</span>
                </div>
                <div className="ml-auto opacity-0 group-hover:opacity-100 transition-opacity hidden sm:block">
                   <span className="text-[10px] font-black text-coffee-400 uppercase tracking-tighter">{analysis.roast}</span>
                </div>
            </div>

            <div className="grid grid-cols-5 sm:flex sm:flex-row gap-2 sm:gap-3 mb-4 sm:mb-6">
              <a 
                href={repo.html_url} 
                target="_blank" 
                rel="noopener noreferrer"
                className="col-span-2 sm:flex-1 min-h-[44px] sm:min-h-[52px] bg-coffee-800 dark:bg-coffee-100 text-white dark:text-coffee-950 py-2 sm:py-3 rounded-xl sm:rounded-2xl font-bold text-[10px] sm:text-xs flex items-center justify-center gap-2 hover:brightness-110 active:scale-[0.98] transition-all shadow-lg"
              >
                <span className="hidden xs:inline">TASTE</span> CODE
                <ExternalLink size={14} className="sm:w-4 sm:h-4" />
              </a>
              <button 
                onClick={copyCloneUrl}
                className={`col-span-2 sm:flex-1 min-h-[44px] sm:min-h-[52px] px-2 sm:px-4 border-2 rounded-xl sm:rounded-2xl flex items-center justify-center gap-1 sm:gap-3 transition-all duration-300 ${
                    copied 
                    ? 'bg-coffee-600 border-coffee-600 text-white' 
                    : 'bg-white dark:bg-coffee-900/50 border-coffee-200 dark:border-coffee-700 text-coffee-800 dark:text-coffee-100 hover:bg-coffee-50'
                }`}
              >
                <span className="text-[10px] sm:text-[11px] font-black uppercase tracking-wider truncate">
                  {copied ? 'COPIED' : 'CLONE'}
                </span>
                <Terminal size={14} className="sm:w-[18px] sm:h-[18px] flex-shrink-0" />
              </button>
              <button
                onClick={() => setShowStats(true)}
                className="col-span-1 min-h-[44px] sm:w-[52px] sm:h-[52px] flex-shrink-0 flex items-center justify-center rounded-xl sm:rounded-2xl border-2 border-coffee-200 dark:border-coffee-700 text-coffee-600 dark:text-coffee-300 hover:bg-coffee-100 dark:hover:bg-coffee-800 transition-all active:scale-95"
                title="View Contribution Activity"
              >
                <BarChart2 size={18} className="sm:w-5 sm:h-5" />
              </button>
            </div>

            <div className="mt-auto pt-4 sm:pt-6 border-t border-coffee-200 dark:border-coffee-800">
                <button 
                    onClick={toggleExpand}
                    className="w-full text-[10px] sm:text-xs font-black tracking-widest text-coffee-500 hover:text-coffee-900 dark:hover:text-white transition-colors flex items-center justify-center gap-2"
                >
                    {expanded ? 'HIDE SPECS' : 'DETAILED NOTES'}
                    <ChevronDown className={`transition-transform duration-500 ${expanded ? 'rotate-180' : ''}`} size={14} />
                </button>
            </div>
          </div>

          <AnimatePresence>
            {expanded && (
              <motion.div 
                initial={{ height: 0, opacity: 0 }} 
                animate={{ height: 'auto', opacity: 1 }} 
                exit={{ height: 0, opacity: 0 }} 
                transition={{ duration: 0.6, ease: [0.33, 1, 0.68, 1] }}
                className="bg-coffee-100/50 dark:bg-black/40 overflow-hidden border-t border-coffee-200 dark:border-coffee-800"
              >
                <div className="p-5 sm:p-8 prose prose-xs sm:prose-sm dark:prose-invert max-w-none prose-p:text-coffee-800 dark:prose-p:text-coffee-200 prose-headings:text-coffee-950 dark:prose-headings:text-white prose-pre:bg-coffee-900 prose-code:text-coffee-400">
                    {loadingReadme ? (
                      <div className="flex flex-col items-center py-8 sm:py-10 gap-4">
                        <div className="w-6 h-6 sm:w-8 sm:h-8 border-4 border-coffee-300 border-t-coffee-800 rounded-full animate-spin" />
                        <span className="text-[10px] sm:text-xs font-bold text-coffee-400 animate-pulse uppercase tracking-widest">Grinding documentation...</span>
                      </div>
                    ) : (
                        <ReactMarkdown remarkPlugins={[remarkGfm]} rehypePlugins={[rehypeRaw]} urlTransform={transformImageUri}>
                            {readme || ''}
                        </ReactMarkdown>
                    )}
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </motion.div>
      <AnimatePresence>
        {showStats && (
            <RepoStatsModal repo={repo} onClose={() => setShowStats(false)} />
        )}
      </AnimatePresence>
    </>
  );
};

