                </button>
            </div>

            <div className="min-h-[220px] sm:min-h-[300px] flex flex-col bg-coffee-50/50 dark:bg-black/30 rounded-2xl sm:rounded-[2.5rem] border border-coffee-100 dark:border-coffee-800/50 p-4 sm:p-10 relative shrink-0">
